import Nav from "@/components/Navbar";

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body className={`${geistSans.variable} ${geistMono.variable}`}>

        <Session>

          <Navbar />

          <AuthWrapper>
            <main className="min-h-screen bg-gray-100">
              {children}
            </main>
          </AuthWrapper>

          <ToastContainer
            position="bottom-center"
            autoClose={3000}
            theme="light"
          />

        </Session>

      </body>
    </html>
  );
}